// Mengimpor modul bawaan Node.js untuk file system dan path
import fs from "fs/promises";
import path from "path";

// Menentukan folder output default untuk project baru
const defaultJalurOutput = path.join(path.resolve("."), "output");

/**
 * @description Membuat struktur folder dan file berdasarkan data array dari model AI.
 * @param {Array<Object>} data - Array objek yang mendeskripsikan struktur project.
 * @param {string} [basePath=defaultJalurOutput] - Path dasar untuk pembuatan file. Defaultnya adalah folder 'output'.
 */
// Fungsi untuk generate aplikasi
async function generateApp(data, basePath = defaultJalurOutput) {
  console.clear();
  console.log(`Sedang membuat/memperbarui project di: ${basePath}`);
  try {
    // Memastikan folder output utama ada jika menggunakan default
    await fs.mkdir(basePath, { recursive: true });

    for (const item of data) {
      // Menggabungkan path dasar dengan lokasi dari item
      const targetPath = path.join(basePath, item.lokasi);
      switch (item.jenis) {
        case "folder":
          await fs.mkdir(targetPath, { recursive: true });
          console.log(`Folder dibuat: ${item.lokasi}`);
          break;
        case "file":
        case "dokumentasi":
        case "config":
          // Memastikan direktori untuk file ini ada sebelum menulis file
          await fs.mkdir(path.dirname(targetPath), { recursive: true });
          await fs.writeFile(targetPath, item.konten || "");
          console.log(`File dibuat: ${item.lokasi}`);
          break;
        default:
          console.warn(`Jenis komponen tidak dikenal: ${item.jenis}`);
          break;
      }
    }
  } catch (err) {
    console.error(`Gagal saat membuat project: ${err.message}`);
  }
}

export default generateApp;

```

