`,
    temperature: parseFloat(process.env.TEMPERATURE) || 0.3,
    responseMimeType: "application/json",
    responseSchema: custom_schema, // Menerapkan skema pada respons
    generationConfig: {
      maxOutputTokens: 15000,
    },
  },
  // Riwayat percakapan akan diisi secara dinamis oleh aplikasi
  history: [],
});

export default model;

