// Mengimpor modul-modul yang diperlukan
import fs from "fs/promises";
import path from "path";

// Kumpulan ekstensi file yang akan diabaikan saat membaca proyek.
const ignoredExtensions = new Set([
    // Gambar
    '.jpg', '.jpeg', '.png', '.gif', '.bmp', '.svg', '.webp', '.ico',
    // Audio
    '.mp3', '.wav', '.ogg', '.flac', '.aac',
    // Video
    '.mp4', '.mov', '.avi', '.mkv', '.webm',
    // Terkompresi
    '.zip', '.rar', '.7z', '.tar', '.gz',
    // Font
    '.woff', '.woff2', '.ttf', '.otf', '.eot',
    // Biner & lainnya
    '.lock', '.log', '.pdf', '.doc', '.docx', '.xls', '.xlsx', '.ppt', '.pptx',
    '.exe', '.dll', '.so', '.class', '.pyc', '.jar', '.bin', '.img', '.iso'
]);

// Kumpulan nama direktori yang akan diabaikan.
const ignoredDirs = new Set(['node_modules', '.git', '.vscode', '.idea', '__pycache__']);

/**
 * @description Membaca seluruh file dalam sebuah direktori secara rekursif dan mengonversinya ke format Markdown.
 * @param {string} dirPath - Path ke direktori project yang akan dibaca.
 * @param {string} [basePath=dirPath] - Path dasar untuk menghitung lokasi relatif (digunakan untuk rekursi).
 * @returns {Promise<string>} - String Markdown yang berisi struktur dan konten project.
 */
// Fungsi untuk membaca project dan mengubahnya menjadi format markdown
async function bacaProjectKeMarkdown(dirPath, basePath = dirPath) {
  let markdownContent = "";
  const entries = await fs.readdir(dirPath, { withFileTypes: true });

  for (const entry of entries) {
    const fullPath = path.join(dirPath, entry.name);

    if (entry.isDirectory()) {
      // Abaikan direktori yang ada di dalam daftar 'ignoredDirs'
      if (ignoredDirs.has(entry.name)) {
        continue;
      }
      // Panggil fungsi ini lagi secara rekursif untuk subdirektori
      markdownContent += await bacaProjectKeMarkdown(fullPath, basePath);
    } else if (entry.isFile()) {
      const fileExtension = path.extname(entry.name).toLowerCase();
      // Abaikan file dengan ekstensi yang ada di dalam daftar 'ignoredExtensions'
      if (ignoredExtensions.has(fileExtension)) {
        continue;
      }

      // Jika file bisa dibaca, lanjutkan proses
      try {
        const relativePath = path.relative(basePath, fullPath).replace(/\\/g, "/");
        const content = await fs.readFile(fullPath, "utf-8");

        markdownContent += `**lokasi**\n${relativePath}\n\n`;
        markdownContent += `**isi konten**\n\`\`\`\n${content}\n\`\`\`\n\n---\n\n`;
      } catch (readError) {
        console.warn(`Peringatan: Gagal membaca file ${fullPath}. Mungkin file ini biner atau rusak.`);
      }
    }
  }

  return markdownContent;
}

// Mengekspor fungsi agar dapat digunakan di file lain
export { bacaProjectKeMarkdown };

```

