import React, { useState, useEffect, useRef } from "react";

import Title from "./componens/Title";
import TextArea from "./componens/TextArea";
import Button from "./componens/Button";
import Footer from "./componens/Footer";
import req_api from "./services/req_api";
import Popup from "./services/alert";
import Suara from "./services/suara.js";
import Storage from "./services/storage.js";
import loadSong from "./sfx/loadSfx.mp3";
import successSong from "./sfx/successSfx.mp3";
import klikSong from "./sfx/klikSfx.mp3";

import AmnesiaButton from "./componens/AmnesiaButton";
import OutputDisplay from "./componens/OutputDisplay";
import ActionButtons from "./componens/ActionButtons";

function App() {
  const [prompt, setPrompt] = useState("");
  const [warn, setWarn] = useState(false);
  const [output, setOutput] = useState("???");
  const [reqButtonOff, setReqButtonOff] = useState(false);
  const [reqMoment, setReqMoment] = useState(false);
  const [reqSukses, setReqSukses] = useState(false);
  const promptRef = useRef(null);
  const loadSuara = new Suara({ src: loadSong, loop: true });
  const successSuara = new Suara({ src: successSong });
  const klikSuara = new Suara({ src: klikSong });

  useEffect(() => {
    promptRef.current.focus();
    if (!Storage.dapatkan()) Storage.simpan([]);
    if (Storage.dapatkan().length > 50) {
      Popup.notif();
      Storage.simpan([]);
    }
  }, []);

  async function onKirim(e) {
    e.preventDefault();
    if (!prompt.trim()) {
      setWarn(true);
      return;
    }
    setWarn(false);
    setReqButtonOff(true);
    setPrompt("");
    setOutput("**mencerna...**");
    loadSuara.play();
    if (!reqMoment) {
      setReqMoment(true);

      const data = await req_api(prompt, setReqSukses);
      loadSuara.stop();
      await setOutput(data);
      successSuara.play();
      setReqButtonOff(false);
      setReqMoment(false);
    }
  }

  return (
    <div className="container d-flex flex-column min-vh-100">
      <div className="d-flex justify-content-center flex-grow-1">
        <div className="w-100" style={{ maxWidth: "500px" }}>
          <div className="d-flex justify-content-end mb-4 mt-1">
            <AmnesiaButton
              reqButtonOff={reqButtonOff}
              reqMoment={reqMoment}
              setPrompt={setPrompt}
              setOutput={setOutput}
              setReqButtonOff={setReqButtonOff}
            />
          </div>

          <Title text="atlas377" />
          <form onSubmit={onKirim} className="mb-4">
            <div className="mb-3">
              <TextArea
                lbl="Pertanyaan"
                row="4"
                text={!prompt ? "Masukkan pertanyaan..." : ""}
                onChange={(e) => setPrompt(e.target.value)}
                value={prompt}
                ref={promptRef}
                required
              />
            </div>

            {warn && (
              <p className="fst-italic text-danger text-md text-center mt-2">
                silakan masukkan pertanyaan..
              </p>
            )}
            <div className="text-center">
              <Button
                disabled={reqButtonOff}
                type="submit"
                sty="btn-dark px-4"
                text="Go"
              />
            </div>
          </form>

          <OutputDisplay output={output} />

          {reqSukses && (
            <ActionButtons
              output={output}
              klikSuara={klikSuara}
              setOutput={setOutput}
              setPrompt={setPrompt}
              setReqSukses={setReqSukses}
              promptRef={promptRef}
            />
          )}
          <p className="text-center mt-4">~~~*~~~</p>
        </div>
      </div>

      <Footer text="atlas377" />
    </div>
  );
}

export default App;

