import React from "react";
import Button from "./Button";
import Popup from "../services/alert";

function ActionButtons({
  output,
  klikSuara,
  setOutput,
  setPrompt,
  setReqSukses,
  promptRef,
}) {
  const handleReset = () => {
    klikSuara.play();
    setOutput("???");
    setPrompt("");
    setReqSukses(false);
    promptRef.current.focus();
  };

  const handleCopyOutput = () => {
    navigator.clipboard
      .writeText(output)
      .then(() => {
        Popup.sukses();
      })
      .catch((err) => {
        Popup.gagal();
      });
  };

  return (
    <div className="text-center d-flex flex-column align-items-center">
      <Button
        type="button"
        sty="btn-dark btn-md"
        onClick={handleReset}
        text="×"
      />
      <Button
        type="button"
        sty="btn-dark btn-md mt-2"
        onClick={handleCopyOutput}
        text="salin"
      />
    </div>
  );
}

export default ActionButtons;

