class Popup {
  static konfirm(setPrompt, setOutput, setReqButton) {
    alertSuara.play();
    Swal.fire({
      title: "Konfirmasi",
      text: "Apakah Anda yakin ingin menghapus memori percakapan anda dengan Atlas?",
      icon: "warning",
      animation: "slide-up",
      showCancelButton: true,
      confirmButtonText: "Ya",
      cancelButtonText: "Tidak",
    }).then((result) => {
      if (result.isConfirmed) {
        const total = Storage.dapatkan().length * 200;
        setOutput("**Mereset...**");
        setReqButton(true);
        hapusSuara.play();
        setTimeout(() => {
          hapusSuara.stop();
          alertSuara.play();
          Swal.fire({
            title: "Info",
            text: "Memori percakapan anda dengan Atlas telah dihapus!",
            icon: "success",
            animation: "slide-up",
            confirmButtonText: "Ok",
          });
          Storage.hapus();
          setPrompt("");
          setOutput("???");
          setReqButton(false);
        }, total);
      } else {
        // tidak menampilkan apa-apa
      }
    });
  }
  static sukses() {
    alertSuara.play();
    Swal.fire({
      title: "Tersalin",
      text: "semua teks berhasil disalin!",
      icon: "success",
      animation: "slide-left",
      timer: 3000,
      showConfirmButton: false,
    });
  }
  static gagal() {
    alertSuara.play();
    Swal.fire({
      title: "Gagal!",
      text: "terjadi kesalahan ketika menyalin semua teks!",
      icon: "error",
      animation: "slide-right",
      timer: 3000,
      showConfirmButton: false,
    });
  }
  static notif() {
    Swal.fire({
      title: "Info",
      text: "Memori Atlas telah melebihi batas penyimpanan jadi ingatan atlas semua percakapan anda dengan Atlas teramnesiakan!",
      icon: "warning",
      animation: "slide-up",
      confirmButtonText: "Ok",
    });
  }
}
export default Popup;

