import Storage from "./storage.js";
import { format } from "date-fns";
import { id } from "date-fns/locale";

async function req_api(prompt, setReqSukses) {
  try {
    const tanggalSekarang = new Date();

    const waktu = format(tanggalSekarang, "EEEE, dd-MMMM-yyyy | HH:mm", {
      locale: id,
    });
    const lawas = (await Storage.dapatkan()) || [];
    if (!import.meta.env.VITE_ROUTE || !import.meta.env.VITE_KEY) {
      return "kredensial tidak lengkap!";
    }

    const response = await fetch(import.meta.env.VITE_ROUTE, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-key": import.meta.env.VITE_KEY,
        "x-waktu": waktu,
      },
      body: JSON.stringify({ prompt, history: lawas }),
    });

    const resType = await response.headers.get("Content-Type");

    if (resType && resType.includes("application/json")) {
      const { message } = await response.json();
      return message;
    } else {
      const message = await response.text();
      const baru = [
        {
          role: "user",
          parts: [{ text: prompt }],
        },
        {
          role: "model",
          parts: [{ text: message }],
        },
      ];
      const dataSimpan = [...lawas, ...baru];
      if (response.status === 200) await Storage.simpan(dataSimpan);
      setReqSukses(true);

      return message;
    }
  } catch (err) {
    return "request gagal!!";
  }
}

export default req_api;

