    "konten": "import Storage from "./storage.js";
import { format } from "date-fns";
import { id } from "date-fns/locale";

async function req_api(prompt, setReqSukses) {
  try {
    const tanggalSekarang = new Date();
    const waktu = format(tanggalSekarang, "EEEE, dd-MMMM-yyyy | HH:mm", { locale: id });
    const lawas = Storage.dapatkan() || [];

    if (!import.meta.env.VITE_ROUTE || !import.meta.env.VITE_KEY) {
      return "Konfigurasi kredensial API tidak lengkap. Silakan periksa file environment Anda.";
    }

    const response = await fetch(import.meta.env.VITE_ROUTE, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-key": import.meta.env.VITE_KEY,
        "x-waktu": waktu,
      },
      body: JSON.stringify({ prompt, history: lawas }),
    });

    const resType = response.headers.get("Content-Type");

    if (resType && resType.includes("application/json")) {
      const { message } = await response.json();
      return message;
    } else {
      const message = await response.text();
      const baru = [
        {
          role: "user",
          parts: [{ text: prompt }],
        },
        {
          role: "model",
          parts: [{ text: message }],
        },
      ];
      const dataSimpan = [...lawas, ...baru];
      if (response.ok) {
        Storage.simpan(dataSimpan);
        setReqSukses(true);
      } else {
        setReqSukses(false);
      }
      return message;
    }
  } catch (err) {
    console.error("Request API Gagal:", err);
    return "Terjadi kesalahan saat menghubungi server. Silakan coba lagi nanti.";
  }
}

export default req_api;
